sql:
SELECT DISTINCT t.task_id, t.task_name
FROM tasks t
JOIN task_dependencies td ON t.task_id = td.task_id;

SELECT task_id, total_time
FROM process_stats
WHERE user_time = 12;

SELECT task_id, total_time
FROM process_stats
WHERE total_time < (SELECT MIN(total_time) FROM process_stats);

external_knowledge:
- 'first user' refers to `user_id` = 0;
- 'initial category' refers to `category_id` = 0;
- 'finished assignments' refer to the tasks with the status 'completed'.

sql:
SELECT t.task_name, s.total_time
FROM tasks t
INNER JOIN process_stats s ON t.task_id = s.task_id;
